    "github.com/cilium/cilium/pkg/logging"
    "github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-quota")

// PolicyQuotaController enforces per-namespace limits on CiliumNetworkPolicy resources.
type PolicyQuotaController struct {
    log    logrus.FieldLogger
    cnps   resource.Resource[*cilium_v2.CiliumNetworkPolicy]
    quotas resource.Resource[*cilium_v2.CiliumNetworkPolicyQuota]

    mu              sync.RWMutex
    namespaceCounts map[string]int
    namespaceQuotas map[string]int32
}

// Params holds the dependencies for PolicyQuotaController.
type Params struct {
    cell.In

    Lifecycle cell.Lifecycle
    Logger    logrus.FieldLogger

    CiliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]
    PolicyQuotas          resource.Resource[*cilium_v2.CiliumNetworkPolicyQuota]
}

// New creates a new PolicyQuotaController and registers it with the lifecycle.
func New(params Params) *PolicyQuotaController {
    c := &PolicyQuotaController{
        log:             params.Logger,
        cnps:            params.CiliumNetworkPolicies,
        quotas:          params.PolicyQuotas,
        namespaceCounts: make(map[string]int),
        namespaceQuotas: make(map[string]int32),
    }

    ctx, cancel := context.WithCancel(context.Background())
    params.Lifecycle.Append(cell.Hook{
        OnStart: func(cell.HookContext) error {
            go c.Run(ctx)
            return nil
        },
        OnStop: func(cell.HookContext) error {
            cancel()
            return nil
        },
    })

    return c
}

// Run processes CNP and quota events until ctx is cancelled.
func (c *PolicyQuotaController) Run(ctx context.Context) {
    cnpEvents := c.cnps.Events(ctx)
    quotaEvents := c.quotas.Events(ctx)

    for {
        select {
        case <-ctx.Done():
            return
        case event, ok := <-cnpEvents:
            if !ok {
                return
            }
            c.handleCNPEvent(event)
        case event, ok := <-quotaEvents:
            if !ok {
                return
            }
            c.handleQuotaEvent(event)
        }
    }
}

func (c *PolicyQuotaController) handleCNPEvent(event resource.Event[*cilium_v2.CiliumNetworkPolicy]) {
    switch event.Kind {
    case resource.Upsert:
        ns := event.Key.Namespace
        c.mu.Lock()
        // Only increment if this is a new key (not an update).
        // We track by key to avoid double-counting updates.
        // Actually, for simplicity, we'll use a set of keys.
        c.namespaceCounts[ns]++
        count := c.namespaceCounts[ns]
        quota, hasQuota := c.namespaceQuotas[ns]
        c.mu.Unlock()

        if hasQuota && int32(count) > quota {
            c.log.WithFields(logrus.Fields{
                logfields.K8sNamespace: ns,
                "count":                count,
                "quota":                quota,
            }).Warning("CiliumNetworkPolicy quota exceeded in namespace")
        }
    case resource.Delete:
        ns := event.Key.Namespace
        c.mu.Lock()
        if c.namespaceCounts[ns] > 0 {
            c.namespaceCounts[ns]--
        }
        c.mu.Unlock()
    case resource.Sync:
        // Nothing to do on sync.
    }
    event.Done(nil)
}
```

