// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package quota

import (
	"context"
	"sync"

	"github.com/cilium/hive/cell"
	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-quota")

// PolicyQuotaController enforces per-namespace limits on CiliumNetworkPolicy
// resources. It watches both CiliumNetworkPolicy and CiliumNetworkPolicyQuota
// objects, maintains per-namespace counts, and logs a warning whenever a
// namespace exceeds its declared quota.
type PolicyQuotaController struct {
	log    logrus.FieldLogger
	cnps   resource.Resource[*cilium_v2.CiliumNetworkPolicy]
	quotas resource.Resource[*cilium_v2.CiliumNetworkPolicyQuota]

	mu              sync.RWMutex
	cnpKeys         map[resource.Key]struct{} // tracks every known CNP key
	namespaceCounts map[string]int            // live count of CNPs per namespace
	namespaceQuotas map[string]int32          // MaxPolicies per namespace
}

// Params holds the dependencies injected into PolicyQuotaController via Hive.
type Params struct {
	cell.In

	Lifecycle cell.Lifecycle
	Logger    logrus.FieldLogger

	CiliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]
	PolicyQuotas          resource.Resource[*cilium_v2.CiliumNetworkPolicyQuota]
}

// New constructs a PolicyQuotaController, registers its start/stop hooks with
// the provided lifecycle, and returns the controller for further use.
func New(params Params) *PolicyQuotaController {
	c := &PolicyQuotaController{
		log:             params.Logger,
		cnps:            params.CiliumNetworkPolicies,
		quotas:          params.PolicyQuotas,
		cnpKeys:         make(map[resource.Key]struct{}),
		namespaceCounts: make(map[string]int),
		namespaceQuotas: make(map[string]int32),
	}

	ctx, cancel := context.WithCancel(context.Background())
	params.Lifecycle.Append(cell.Hook{
		OnStart: func(cell.HookContext) error {
			go c.Run(ctx)
			return nil
		},
		OnStop: func(cell.HookContext) error {
			cancel()
			return nil
		},
	})

	return c
}

// Run processes CiliumNetworkPolicy and CiliumNetworkPolicyQuota events until
// ctx is cancelled. It is safe to call Run directly in tests without going
// through the Hive lifecycle.
func (c *PolicyQuotaController) Run(ctx context.Context) {
	cnpEvents := c.cnps.Events(ctx)
	quotaEvents := c.quotas.Events(ctx)

	for {
		select {
		case <-ctx.Done():
			return
		case event, ok := <-cnpEvents:
			if !ok {
				return
			}
			c.handleCNPEvent(event)
		case event, ok := <-quotaEvents:
			if !ok {
				return
			}
			c.handleQuotaEvent(event)
		}
	}
}

// IsOverQuota reports whether the given namespace has reached or exceeded its
// declared CiliumNetworkPolicy quota. Returns false when no quota is defined.
func (c *PolicyQuotaController) IsOverQuota(namespace string) bool {
	c.mu.RLock()
	defer c.mu.RUnlock()
	quota, hasQuota := c.namespaceQuotas[namespace]
	if !hasQuota {
		return false
	}
	return int32(c.namespaceCounts[namespace]) >= quota
}

// NamespaceCount returns the number of CiliumNetworkPolicy resources currently
// tracked in the given namespace.
func (c *PolicyQuotaController) NamespaceCount(namespace string) int {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.namespaceCounts[namespace]
}

// handleCNPEvent processes a single CiliumNetworkPolicy event.
func (c *PolicyQuotaController) handleCNPEvent(event resource.Event[*cilium_v2.CiliumNetworkPolicy]) {
	switch event.Kind {
	case resource.Upsert:
		ns := event.Key.Namespace
		c.mu.Lock()
		if _, exists := c.cnpKeys[event.Key]; !exists {
			// New policy — increment the namespace counter.
			c.cnpKeys[event.Key] = struct{}{}
			c.namespaceCounts[ns]++
		}
		count := c.namespaceCounts[ns]
		quota, hasQuota := c.namespaceQuotas[ns]
		c.mu.Unlock()

		if hasQuota && int32(count) > quota {
			c.log.WithFields(logrus.Fields{
				logfields.K8sNamespace: ns,
				"currentCount":         count,
				"maxPolicies":          quota,
			}).Warning("CiliumNetworkPolicy quota exceeded in namespace")
		}

	case resource.Delete:
		ns := event.Key.Namespace
		c.mu.Lock()
		if _, exists := c.cnpKeys[event.Key]; exists {
			delete(c.cnpKeys, event.Key)
			if c.namespaceCounts[ns] > 0 {
				c.namespaceCounts[ns]--
			}
		}
		c.mu.Unlock()

	case resource.Sync:
		// Initial list replay is complete; no action required.
	}

	event.Done(nil)
}

// handleQuotaEvent processes a single CiliumNetworkPolicyQuota event.
func (c *PolicyQuotaController) handleQuotaEvent(event resource.Event[*cilium_v2.CiliumNetworkPolicyQuota]) {
	switch event.Kind {
	case resource.Upsert:
		ns := event.Key.Namespace
		maxPolicies := event.Object.Spec.MaxPolicies
		c.mu.Lock()
		c.namespaceQuotas[ns] = maxPolicies
		count := c.namespaceCounts[ns]
		c.mu.Unlock()

		c.log.WithFields(logrus.Fields{
			logfields.K8sNamespace: ns,
			"maxPolicies":          maxPolicies,
		}).Debug("Updated CiliumNetworkPolicy quota for namespace")

		if int32(count) > maxPolicies {
			c.log.WithFields(logrus.Fields{
				logfields.K8sNamespace: ns,
				"currentCount":         count,
				"maxPolicies":          maxPolicies,
			}).Warning("Namespace already exceeds newly applied CiliumNetworkPolicy quota")
		}

	case resource.Delete:
		ns := event.Key.Namespace
		c.mu.Lock()
		delete(c.namespaceQuotas, ns)
		c.mu.Unlock()

		c.log.WithField(logfields.K8sNamespace, ns).
			Debug("Removed CiliumNetworkPolicy quota for namespace")

	case resource.Sync:
		// Initial list replay is complete; no action required.
	}

	event.Done(nil)
}

