package quota

import (
	"context"
	"errors"
	"testing"
	"time"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
)

// fakeResource is a test double for resource.Resource[T] backed by a channel.
// Sending an event on the channel drives the controller under test.
type fakeResource[T runtime.Object] chan resource.Event[T]

func (fr fakeResource[T]) Observe(_ context.Context, _ func(resource.Event[T]), complete func(error)) {
	complete(errors.New("not implemented"))
}

func (fr fakeResource[T]) Events(_ context.Context, _ ...resource.EventsOpt) <-chan resource.Event[T] {
	return fr
}

func (fr fakeResource[T]) Store(context.Context) (resource.Store[T], error) {
	return nil, errors.New("not implemented")
}

// send delivers an event synchronously: it blocks until the controller calls
// event.Done, then returns the error passed to Done.
func (fr fakeResource[T]) send(ev resource.Event[T]) error {
	done := make(chan error, 1)
	ev.Done = func(err error) { done <- err }
	fr <- ev
	return <-done
}

// upsertCNP sends an Upsert event for the given CiliumNetworkPolicy.
func upsertCNP(t *testing.T, ch fakeResource[*cilium_v2.CiliumNetworkPolicy], cnp *cilium_v2.CiliumNetworkPolicy) {
	t.Helper()
	err := ch.send(resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Upsert,
		Key:    resource.NewKey(cnp),
		Object: cnp,
	})
	assert.NoError(t, err)
}

// deleteCNP sends a Delete event for the given CiliumNetworkPolicy.
func deleteCNP(t *testing.T, ch fakeResource[*cilium_v2.CiliumNetworkPolicy], cnp *cilium_v2.CiliumNetworkPolicy) {
	t.Helper()
	err := ch.send(resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Delete,
		Key:    resource.NewKey(cnp),
		Object: cnp,
	})
	assert.NoError(t, err)
}

// syncCNPs sends a Sync event on the CNP channel.
func syncCNPs(t *testing.T, ch fakeResource[*cilium_v2.CiliumNetworkPolicy]) {
	t.Helper()
	err := ch.send(resource.Event[*cilium_v2.CiliumNetworkPolicy]{Kind: resource.Sync})
	assert.NoError(t, err)
}

// upsertQuota sends an Upsert event for the given CiliumNetworkPolicyQuota.
func upsertQuota(t *testing.T, ch fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], q *cilium_v2.CiliumNetworkPolicyQuota) {
	t.Helper()
	err := ch.send(resource.Event[*cilium_v2.CiliumNetworkPolicyQuota]{
		Kind:   resource.Upsert,
		Key:    resource.NewKey(q),
		Object: q,
	})
	assert.NoError(t, err)
}

// deleteQuota sends a Delete event for the given CiliumNetworkPolicyQuota.
func deleteQuota(t *testing.T, ch fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], q *cilium_v2.CiliumNetworkPolicyQuota) {
	t.Helper()
	err := ch.send(resource.Event[*cilium_v2.CiliumNetworkPolicyQuota]{
		Kind:   resource.Delete,
		Key:    resource.NewKey(q),
		Object: q,
	})
	assert.NoError(t, err)
}

// newController builds a PolicyQuotaController wired to the provided fake
// channels and starts Run in a background goroutine. The returned cancel
// function stops the controller; it is automatically called at test cleanup.
func newController(
	t *testing.T,
	cnpCh fakeResource[*cilium_v2.CiliumNetworkPolicy],
	quotaCh fakeResource[*cilium_v2.CiliumNetworkPolicyQuota],
) *PolicyQuotaController {
	t.Helper()

	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)

	c := &PolicyQuotaController{
		log:             logrus.NewEntry(logger),
		cnps:            cnpCh,
		quotas:          quotaCh,
		cnpKeys:         make(map[resource.Key]struct{}),
		namespaceCounts: make(map[string]int),
		namespaceQuotas: make(map[string]int32),
	}

	ctx, cancel := context.WithCancel(context.Background())
	t.Cleanup(cancel)
	go c.Run(ctx)

	return c
}

// makeCNP is a convenience constructor for CiliumNetworkPolicy test fixtures.
func makeCNP(namespace, name string) *cilium_v2.CiliumNetworkPolicy {
	return &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: namespace,
			Name:      name,
		},
	}
}

// makeQuota is a convenience constructor for CiliumNetworkPolicyQuota fixtures.
func makeQuota(namespace, name string, max int32) *cilium_v2.CiliumNetworkPolicyQuota {
	return &cilium_v2.CiliumNetworkPolicyQuota{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: namespace,
			Name:      name,
		},
		Spec: cilium_v2.CiliumNetworkPolicyQuotaSpec{MaxPolicies: max},
	}
}

// TestCNPUpsertIncrementsCount verifies that upserting a new CNP increments
// the namespace counter.
func TestCNPUpsertIncrementsCount(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy], 1)
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], 1)
	c := newController(t, cnpCh, quotaCh)

	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-1"))
	assert.Equal(t, 1, c.NamespaceCount("ns-a"))

	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-2"))
	assert.Equal(t, 2, c.NamespaceCount("ns-a"))

	// A different namespace must not affect ns-a.
	upsertCNP(t, cnpCh, makeCNP("ns-b", "policy-1"))
	assert.Equal(t, 2, c.NamespaceCount("ns-a"))
	assert.Equal(t, 1, c.NamespaceCount("ns-b"))
}

// TestCNPUpdateDoesNotDoubleCount verifies that re-upserting the same CNP key
// (an update) does not increment the counter a second time.
func TestCNPUpdateDoesNotDoubleCount(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy], 1)
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], 1)
	c := newController(t, cnpCh, quotaCh)

	cnp := makeCNP("ns-a", "policy-1")
	upsertCNP(t, cnpCh, cnp)
	assert.Equal(t, 1, c.NamespaceCount("ns-a"))

	// Simulate an update by upserting the same key again.
	upsertCNP(t, cnpCh, cnp)
	assert.Equal(t, 1, c.NamespaceCount("ns-a"), "update must not double-count")
}

// TestCNPDeleteDecrementsCount verifies that deleting a CNP decrements the
// namespace counter.
func TestCNPDeleteDecrementsCount(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy], 1)
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], 1)
	c := newController(t, cnpCh, quotaCh)

	cnp1 := makeCNP("ns-a", "policy-1")
	cnp2 := makeCNP("ns-a", "policy-2")

	upsertCNP(t, cnpCh, cnp1)
	upsertCNP(t, cnpCh, cnp2)
	assert.Equal(t, 2, c.NamespaceCount("ns-a"))

	deleteCNP(t, cnpCh, cnp1)
	assert.Equal(t, 1, c.NamespaceCount("ns-a"))

	deleteCNP(t, cnpCh, cnp2)
	assert.Equal(t, 0, c.NamespaceCount("ns-a"))
}

// TestCNPDeleteUnknownKeyIsNoop verifies that deleting a key that was never
// upserted does not underflow the counter.
func TestCNPDeleteUnknownKeyIsNoop(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy], 1)
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], 1)
	c := newController(t, cnpCh, quotaCh)

	deleteCNP(t, cnpCh, makeCNP("ns-a", "ghost-policy"))
	assert.Equal(t, 0, c.NamespaceCount("ns-a"))
}

// TestSyncEventIsHandled verifies that a Sync event is processed without error
// and does not alter any counts.
func TestSyncEventIsHandled(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy], 1)
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], 1)
	c := newController(t, cnpCh, quotaCh)

	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-1"))
	syncCNPs(t, cnpCh)
	assert.Equal(t, 1, c.NamespaceCount("ns-a"))
}

// TestQuotaUpsertSetsLimit verifies that upserting a quota object records the
// MaxPolicies value for the namespace.
func TestQuotaUpsertSetsLimit(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy], 1)
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], 1)
	c := newController(t, cnpCh, quotaCh)

	upsertQuota(t, quotaCh, makeQuota("ns-a", "quota", 5))

	c.mu.RLock()
	limit, ok := c.namespaceQuotas["ns-a"]
	c.mu.RUnlock()

	assert.True(t, ok, "quota should be recorded")
	assert.Equal(t, int32(5), limit)
}

// TestQuotaDeleteRemovesLimit verifies that deleting a quota object removes
// the namespace limit so that IsOverQuota always returns false afterwards.
func TestQuotaDeleteRemovesLimit(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy], 1)
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], 1)
	c := newController(t, cnpCh, quotaCh)

	q := makeQuota("ns-a", "quota", 1)
	upsertQuota(t, quotaCh, q)
	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-1"))
	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-2"))
	assert.True(t, c.IsOverQuota("ns-a"))

	deleteQuota(t, quotaCh, q)
	assert.False(t, c.IsOverQuota("ns-a"), "no quota means never over-quota")
}

// TestIsOverQuotaNoQuota verifies that IsOverQuota returns false when no quota
// has been defined for the namespace.
func TestIsOverQuotaNoQuota(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy], 1)
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], 1)
	c := newController(t, cnpCh, quotaCh)

	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-1"))
	assert.False(t, c.IsOverQuota("ns-a"))
}

// TestIsOverQuotaAtLimit verifies that IsOverQuota returns true when the count
// equals MaxPolicies (at-limit is treated as over-quota).
func TestIsOverQuotaAtLimit(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy], 1)
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], 1)
	c := newController(t, cnpCh, quotaCh)

	upsertQuota(t, quotaCh, makeQuota("ns-a", "quota", 2))
	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-1"))
	assert.False(t, c.IsOverQuota("ns-a"), "one policy under a limit of two is not over-quota")

	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-2"))
	assert.True(t, c.IsOverQuota("ns-a"), "count equal to limit is over-quota")
}

// TestIsOverQuotaExceedsLimit verifies that IsOverQuota returns true when the
// count strictly exceeds MaxPolicies.
func TestIsOverQuotaExceedsLimit(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy], 1)
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], 1)
	c := newController(t, cnpCh, quotaCh)

	upsertQuota(t, quotaCh, makeQuota("ns-a", "quota", 1))
	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-1"))
	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-2"))
	assert.True(t, c.IsOverQuota("ns-a"))
}

// TestQuotaUpdatedAfterPoliciesExist verifies that applying a quota to a
// namespace that already has policies correctly reflects the over-quota state.
func TestQuotaUpdatedAfterPoliciesExist(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy], 1)
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], 1)
	c := newController(t, cnpCh, quotaCh)

	// Add three policies before any quota is set.
	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-1"))
	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-2"))
	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-3"))
	assert.False(t, c.IsOverQuota("ns-a"), "no quota yet")

	// Now apply a quota that is already exceeded.
	upsertQuota(t, quotaCh, makeQuota("ns-a", "quota", 2))
	assert.True(t, c.IsOverQuota("ns-a"), "three policies exceed a limit of two")
}

// TestMultipleNamespacesAreIsolated verifies that quota enforcement in one
// namespace does not affect another.
func TestMultipleNamespacesAreIsolated(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy], 1)
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota], 1)
	c := newController(t, cnpCh, quotaCh)

	upsertQuota(t, quotaCh, makeQuota("ns-a", "quota", 1))
	upsertQuota(t, quotaCh, makeQuota("ns-b", "quota", 3))

	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-1"))
	upsertCNP(t, cnpCh, makeCNP("ns-a", "policy-2"))
	upsertCNP(t, cnpCh, makeCNP("ns-b", "policy-1"))

	assert.True(t, c.IsOverQuota("ns-a"), "ns-a is over its quota of 1")
	assert.False(t, c.IsOverQuota("ns-b"), "ns-b has 1 policy under a quota of 3")
	assert.Equal(t, 2, c.NamespaceCount("ns-a"))
	assert.Equal(t, 1, c.NamespaceCount("ns-b"))
}

// TestRunStopsOnContextCancellation verifies that Run exits promptly when its
// context is cancelled.
func TestRunStopsOnContextCancellation(t *testing.T) {
	cnpCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicy])
	quotaCh := make(fakeResource[*cilium_v2.CiliumNetworkPolicyQuota])

	logger := logrus.New()
	c := &PolicyQuotaController{
		log:             logrus.NewEntry(logger),
		cnps:            cnpCh,
		quotas:          quotaCh,
		cnpKeys:         make(map[resource.Key]struct{}),
		namespaceCounts: make(map[string]int),
		namespaceQuotas: make(map[string]int32),
	}

	ctx, cancel := context.WithCancel(context.Background())
	done := make(chan struct{})
	go func() {
		c.Run(ctx)
		close(done)
	}()

	cancel()

	select {
	case <-done:
		// Run exited as expected.
	case <-time.After(2 * time.Second):
		t.Fatal("Run did not exit after context cancellation")
	}
}
